sql:
SELECT AVG(traffic_volume) AS average_traffic_volume
FROM structures
WHERE priority_rank = 'Low' AND sufficiency_rating BETWEEN 51 AND 100;

SELECT priority_rank, COUNT(structure_id) AS structure_count
FROM structures
GROUP BY priority_rank;

SELECT name
FROM structures
WHERE interim_inspection_required = 1;

SELECT COUNT(structure_id) 
FROM structures 
WHERE priority_rank = 'High';

SELECT name, sufficiency_rating
FROM structures
ORDER BY sufficiency_rating DESC;

SELECT structure_number
FROM structures
WHERE sufficiency_rating = (SELECT MAX(sufficiency_rating) FROM structures);

external_knowledge:
- 'High sufficiency ratings' refer to structures with a sufficiency rating greater than 90;
- 'Low maintenance costs' refer to structures with maintenance costs below the average maintenance cost;
- 'Recently inspected' refers to inspections within the last year;
- 'High priority' refers to structures with a priority rank of 'High'.

- "Stewards" refer to the owners or authorities responsible for the structures;
- "Robust and well-cared-for" structures are those with the highest condition and sufficiency ratings within their owner groups;
- "Recently inspected and maintained" means the structures have non-NULL dates for the most recent inspection and maintenance activities.

sql:
SELECT COUNT(structure_id)
FROM structures
WHERE maintenance_authority = 'HUNTERDON' AND owner = 'COUNTY';

external_knowledge:
- 'Bridges' are a type of infrastructure that requires regular maintenance and inspections to ensure safety and functionality;
- 'Interim inspections' are check-ups performed between regular maintenance schedules;
- 'Low priority' indicates that the structure is not considered critical but still needs attention;
- 'State Department of Transportation' is a government agency responsible for maintaining public infrastructure.

- `structure_number` is a unique identifier for each structure, similar to a building's address;
- `total_maintenance_cost` represents the sum of all costs associated with maintenance activities for a structure;
- `average_assessment_cost` represents the mean cost of all structural assessments for a structure.

sql:
SELECT AVG(sufficiency_rating) AS average_sufficiency_rating
FROM structures
WHERE interim_inspection_required = 1 AND priority_rank = 'High';

SELECT AVG(maintenance_cost) AS average_maintenance_cost
FROM maintenance_activities
WHERE activity_type = 'Repair';

external_knowledge:
- "Completed maintenance activities" refer to maintenance activities that have been fully executed and recorded as completed;
- "Maintenance costs" are the financial expenses associated with the maintenance activities;
- "Maintenance authority" is the organization responsible for overseeing the maintenance of the structures.

sql:
SELECT AVG(sufficiency_rating) AS average_sufficiency_rating
FROM structures
WHERE sufficiency_rating IS NOT NULL AND priority_rank != 'NR';

SELECT DISTINCT owner
FROM structures
WHERE priority_rank = 'High';

SELECT AVG(sufficiency_rating) AS average_sufficiency_rating
FROM structures
WHERE priority_rank = 'Low';

external_knowledge:
- "Below par" refers to a sufficiency rating below the average sufficiency rating of all structures;
- "Inspections completed" refers to the inspection status being 'Completed';
- "Inspected more than once" means the structure has more than one inspection record.

sql:
SELECT structure_number
FROM structures
WHERE priority_rank = 'High' AND interim_inspection_required = 1;

SELECT AVG(sufficiency_rating) AS average_sufficiency_rating
FROM structures
WHERE maintenance_authority = 'HUNTERDON' AND sufficiency_rating > 50;

SELECT name 
FROM structures 
WHERE sufficiency_rating > 50 AND priority_rank = 'High';

external_knowledge:
- 'State Department of Transportation' refers to a government agency responsible for managing and maintaining transportation infrastructure;
- 'Sufficiency rating' is a measure of the overall condition and functionality of a structure, typically out of 100;
- 'Average daily traffic volume' is the number of vehicles that pass through a structure on an average day.

- "health score" refers to the sufficiency rating of the structures (out of 100);
- "less critical structures" refers to structures with a priority rank of 'Low';
- "not been checked up recently" means no interim inspection has been required and the next inspection date is more than one year from the current date.
